#include <stdio.h>

union Data {
    int i;
    float f;
    char c;
};

int main() {
    union Data d;

    printf("Size of union: %zu bytes\n", sizeof(union Data));

    d.i = 65;
    printf("After d.i = 65: d.i = %d, d.c = %c\n", d.i, d.c);

    d.f = 3.14;
    printf("After d.f = 3.14: d.f = %.2f, d.i = %d\n", d.f, d.i);

    d.c = 'A';
    printf("After d.c = 'A': d.c = %c, d.i = %d\n", d.c, d.i);

    return 0;
}

#include <stdio.h>

union IntBytes {
    unsigned int value;
    unsigned char bytes[4];
};

int main() {
    union IntBytes ib;

    ib.value = 0x12345678;

    printf("Integer value: 0x%X\n", ib.value);
    printf("Bytes (hex): ");
    for(int i = 0; i < 4; i++) {
        printf("%02X ", ib.bytes[i]);
    }
    printf("\n");

    printf("\nThis shows %s-endian system\n",
           ib.bytes[0] == 0x78 ? "little" : "big");

    return 0;
}

#include <stdio.h>
#include <string.h>

enum IDType { NUMERIC, ALPHANUMERIC };

struct EmployeeID {
    enum IDType type;
    union {
        int numeric_id;
        char alphanumeric[20];
    } id;
};

void setNumericID(struct EmployeeID *emp, int num) {
    emp->type = NUMERIC;
    emp->id.numeric_id = num;
}

void setAlphanumericID(struct EmployeeID *emp, char *code) {
    emp->type = ALPHANUMERIC;
    strcpy(emp->id.alphanumeric, code);
}

void displayID(struct EmployeeID *emp) {
    if(emp->type == NUMERIC) {
        printf("Employee ID: %d (Numeric)\n", emp->id.numeric_id);
    } else {
        printf("Employee ID: %s (Alphanumeric)\n", emp->id.alphanumeric);
    }
}

int main() {
    struct EmployeeID emp1, emp2;

    setNumericID(&emp1, 1001);
    setAlphanumericID(&emp2, "EMP-2024-A");

    displayID(&emp1);
    displayID(&emp2);

    printf("\nSize of EmployeeID: %zu bytes\n", sizeof(struct EmployeeID));

    return 0;
}

#include <stdio.h>

struct Message {
    int type;
    union {
        int intValue;
        float floatValue;
        char text[50];
    };
};

void processMessage(struct Message *msg) {
    switch(msg->type) {
        case 1:
            printf("Integer value: %d\n", msg->intValue);
            break;
        case 2:
            printf("Float value: %.2f\n", msg->floatValue);
            break;
        case 3:
            printf("Text: %s\n", msg->text);
            break;
        default:
            printf("Unknown message type\n");
    }
}

int main() {
    struct Message msg1, msg2, msg3;

    msg1.type = 1;
    msg1.intValue = 42;

    msg2.type = 2;
    msg2.floatValue = 3.14159;

    msg3.type = 3;
    strcpy(msg3.text, "Hello Union!");

    processMessage(&msg1);
    processMessage(&msg2);
    processMessage(&msg3);

    printf("\nSize of Message struct: %zu bytes\n", sizeof(struct Message));

    return 0;
}
